%[text] # Polynomials, Curve-fitting and Interpolation
%[text] # 다항식, 커브 피팅, 인터폴레이션
myName = "양연우"; %[control:editfield:7d85]{"position":[10,15]}
disp("나의 이름은 " + myName + " 입니다."); %[output:8a76d37d]
%%
%[text] ## 다항식 / 多項式 / Polynomial
%[text] 다항식(多項式)은 한자로 \*\*많을 다(多), 항목 항(項), 법식 식(式)\*\*을 쓰며, '항이 여러 개(많다) 있는 식'을 뜻합니다. 1개 이상의 단항식 합으로 이루어진 식을 의미합니다. 
%[text] *참고: 하나뿐인 항으로 이루어진 식은 '단항식(單項式)'이라 합니다.* 
%[text] [https://kr.mathworks.com/help/releases/R2025b/matlab/polynomials.html](https://kr.mathworks.com/help/releases/R2025b/matlab/polynomials.html) 
%[text] ### 다항식의 예
%[text] $3x^2 +2x - 1$ : 2차 다항식
p = [3 2 -1]  % 다항식의 MATLAB 표현: 최고차 항부터 계수만 벡터로 나타냄  %[output:9c4751d4]
%%
%[text] #### 연습문제 1: 다음 다항식을 MATLAB으로 나타내시오.
%[text]  1\. $x^4 - x^2 + 2$ 
p1 = [1 0 -1 0 2] % 4차 다항식  %[output:5ce2216f]
%[text]  2\.  $1 -5x^5 + 3x^3 -x$
p2 = [-5 0 3 0 -1 1] % 5차 다항식 %[output:17dd5a80]
%%
%[text] #### 연습문제 2: 다음 MATLAB 표현에 해당하는 다항식을 수식으로 나타내시오.
p3 = [1 0 1 0 -1] % 4차 다항식 %[output:505af015]
%[text]  1\. 다항식 수식: $x^4 + x^2 -1$
p4 = -2:2:2 % 2차 다항식 [-2 0 2] %[output:92212776]
%[text]  2\. 다항식 수식: $-2x^2 + 2$
%%
%[text] ### 다항식이 아닌 것
%[text] 다항식(polynomial)은 변수의 덧셈, 뺄셈, 곱셈, 그리고 음이 아닌 정수 지수(차수)로 이루어진 식입니다. 따라서 **분모에 문자가 있는 식, 루트 안에 문자가 있는 식, 혹은 절대값 기호가 있는 식**은 다항식이 아닙니다. 
%[text] **다항식이 아닌 주요 예시**
%[text] - 분모에 변수가 있는 식: $\\frac{1}{x}$ ![](text:image:08c1)= $x^{-1}$(양의 정수 혹은 0이어야 함) , $\\frac{2x-1}{x^2}$ ![](text:image:1c77)등
%[text] - 루트 안에 문자가 있는 무리식: $\\sqrt{x}$ ![](text:image:139a) = $x^{1/2}$, ![](text:image:34a5) $\\sqrt{x^2-1}$ 등
%[text] - 절대값 기호가 포함된 식: ![](text:image:1016)![](text:image:1907)![](text:image:3c3f)$|x|$, $|2x-1|$ ![](text:image:79bb)![](text:image:6cac)![](text:image:6d62)![](text:image:3f1f) 등
%[text] - 지수에 문자가 있는 식: $2^x$![](text:image:39c6), ![](text:image:9a0d) $e^{x^2-1}$등  \
%[text] 다항식은 $2x^2-x+5$와 같이 각 항이 수와 문자의 곱으로만 이루어져야 합니다. 
%[text] #### 연습문제 3: 다항식을 나타낸 그래프가 아닌 것을 모두 고르시오.
%[text] ![](text:image:0ef1)![](text:image:74cc)![](text:image:0fd2)
%[text] 1: $\\frac{1}{x}$의 그래프
%[text] 2 쌍곡선 그래프: $x^2 - y^2 = 1$
%[text] 3 탄젠트 그래프, 삼각함수: $\\tan{x}$
%%
%[text] ### 다항식의 계산
%[text] [`polyval`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/polyval.html)
%[text] 다항식 $f(x) = 3.75x^4 - 13.75x^2 + 5$ 에서 $x$가 -2 ~ 2의 범위를 가질 때 $f(x)$의 값은 다음과 같이 구합니다.
clear;
p = [3.75 0 -13.75 0 5]  % 다항식의 계수 %[output:618ddfdb]
x = linspace(-2, 2, 100); % x 값
y = polyval(p, x); % y 값
figure; %[output:7a2c12ea]
plot(x, y); grid on; %[output:7a2c12ea]
%%
%[text] #### 연습문제 4: $f(x) = 0.2x^3 -x^2 -x +1$의 그래프를 $-2 \< x \< 6$의 범위에 대하여 그리시오.
% your code
p = [0.2 -1 -1 1];
x = linspace(-2, 6, 100);
y = polyval(p, x);
h = plot(x, y, "LineWidth", 1.5); grid on; %[output:7bf9587f]
h.LineStyle = ":"; %[output:7bf9587f]
h.Color = 'g'; %[output:7bf9587f]
axis([-2 6 -7 2]) %[output:7bf9587f]
%%
%[text] ### 다항식의 근
%[text] [`roots`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/roots.html)
%[text] $f(x)=0$이 되는 $x$를 다항식의 근(뿌리, roots)이라고 합니다. 
%[text] 다항식 $f(x) = x^5 -5x^3 +4x$ 의 근은 다음과 같이 구합니다. 
clear;
p = [1 0 -5 0 4 0] %[output:21719aea]
r = roots(p) %근을 구해준다 %[output:81e6a9c5]
%%
%[text] $-2.5 \< x \< 2.5$의 범위에서 그래프를 그리고 근을 나타내면 다음과 같습니다.
x = linspace(-2.5, 2.5, 100);
y = polyval(p, x);
z = zeros(size(r)); % 근의 y값은 0이기에 zeros 사용 & 개수 맞춰주기 위해 size 사용 
plot(x, y, 'b-', r, z, 'ro'); %[output:5fc976f0]
grid on; ylim(4*[-1 1]); % 보수 쉽게 만든다 %[output:5fc976f0]
%%
%[text] #### 연습문제 5: 다항식 $f(x) = -2x -x^2 +x^3$의 그래프를 $-2 \< x \< 3$, $-5 \< y \< 5$의 범위에서 그리고 근을 나타내시오.
% your code
clear;
p = [1 -1 -2 0];
x = linspace(-2, 3, 100);
y = polyval(p, x);

r = roots(p);
z = zeros(size(r));

h = plot(x, y, 'r-', r, z, 'bo'); %[output:1fda36a6]
ylim(5*[-1 1]); grid on; %[output:1fda36a6]
%%
%[text] ### 다항식의 극대, 극소 (local maxima, local minima)
%[text] \*\*다항식의 그래프에서 기울기가 0일 때 극대 또는 극소값을 갖는다.
%[text] 기울기가 0일 때는 다항식의 미분값은 0이 됩니다. 
%[text] 다항식 `p를 미분한 다항식은 polyder(p)로 구할 수 있습니다.`
%[text] [`polyder`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/polyder.html)
%[text] 다항식 $f(x) = -2x -x^2 +x^3$을 미분한 다항식 $q(x)= f^{'}(x)$는 다음과 같이 구할 수 있습니다.
clear;
p = [1 -1 -2 0];
q = polyder(p) %[output:2b965e42]
%[text] 따라서 $q(x)=3x^2 -2x -2$가 되는 것을 알 수 있습니다. 
%%
%[text] 미분값이 0일때 $f(x)$는 극대 또는 극소값을 갖습니다. 미분값 $q(x)=0$을 만족하는 $x$값은 다음과 같이 구할 수 있습니다. 
qz = roots(q) % qzero %[output:9eeabf5d]
%[text] 이 때 $f(x)$ 값은 극대 또는 극소값에 해당하며 다음과 같이 구할 수 있습니다. 
pm = polyval(p, qz) %pmax, min %[output:259caaf9]
%%
%[text] 다항식 $f(x) = -2x -x^2 +x^3$의 그래프를 $-2 \< x \< 3$, $-5 \< y \< 5$의 범위에서 극대, 극소값과 함께 그래프로 나타내면 다음과 같습니다. 
x = linspace(-2, 3, 100);
y = polyval(p, x);
plot(x, y, 'r-', qz, pm, 'ro', "MarkerFaceColor","none"); %[output:1134dd83]
grid on; ylim(5*[-1 1]); %[output:1134dd83]
xlabel("$x$", "Interpreter","latex"); %[output:1134dd83]
ylabel("$f(x)$", "Interpreter","latex"); %[output:1134dd83]
%[text] 
%%
%[text] #### 연습문제 6: 다항식 $f(x) = x^5 -5x^3 +4x$ 의 그래프를  $-2.5 \< x \< 2.5$, $-5 \< y \< 5$의 범위에서 그리고, 근과 극대 극소를 함께 나타내시오.
%[text] ![](text:image:8222)
% your code 
p = [1 0 -5 0 4 0];
x = linspace(-3, 3, 100);
y = polyval(p, x);

r = roots(p);
z = zeros(size(r));

q = polyder(p);
qz = roots(q);
pm = polyval(p, qz);

plot(x, y, 'r-');  %[output:3e1438e3]
hold on; %[output:3e1438e3]
h = plot(r, z, 'ro', 'MarkerFaceColor', 'none'); %[output:3e1438e3]
plot(qz, pm, 'ro', 'MarkerFaceColor', 'r'); %[output:3e1438e3]
hold off; %[output:3e1438e3]

xlabel("$x$", "Interpreter", "latex"); %[output:3e1438e3]
ylabel("$y$", "Interpreter", "latex"); %[output:3e1438e3]
yticks([-5 0 5]) %[output:3e1438e3]
text(-0.5, 3, "$x^5-5x^3+4x$", "Interpreter", "Latex"); %[output:3e1438e3]
xlim(3*[-1 1]); ylim(5*[-1 1]); grid on; %[output:3e1438e3]
%%
%[text] ## 커브 피팅 / Curve Fitting
%[text] [`polyfit`](http://mathworks.com/help/releases/R2025b/matlab/ref/polyfit.html)
%[text] $n$개 점의 $(x,y)$ 좌표를 나타내는 $n \\times 2$ 행렬을 $C$라고 할 때, 이 점들을 가장 잘 표현하는 $m$차 다항식의 계수 $p$는 다음과 같이 구할 수 있습니다.
%[text] `p = polyfit(C(:,1), C(:,2), m)`
%[text] `즉, polyfit()의 첫 번째 인수는 점들의` $x$좌표, 두 번째 인수는 $y$좌표이며, 세 번째 인수는 구하려는 다항식의 차수(order)입니다.
%%
%[text] ### 두 점을 통과하는 직선 (1차 다항식)
%[text] 두 점 (-2, -1), (1, 2)를 통과하는 직선의 방정식은 다음과 같이 구할 수 있습니다.
C = [-2 -1; 1 2]; xc = C(:,1); yc = C(:,2);
p = polyfit(xc, yc, 1) % y = ax + b --> p = [a b] %[output:1e8b0fa2]
x = linspace(-3, 2, 100);
y = polyval(p, x); % y = x + 1
plot(x, y, 'b-', xc, yc, 'ro', "MarkerFaceColor","auto"); %[output:32e0492b]
grid on; axis equal; %[output:32e0492b]
%%
%[text] #### 10개의 랜덤 점을 통과하는 직선들
%[text] [`randi`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.randi.html)
%[text] $-5 \\sim 5$사이의 랜덤 두 점들을 통과하는 직선을 10개 그려볼까요?
K = 10;
Cx = randi(50*[-1 1], 2, K)/10 %점 10개가 겹치는 경우를 피하기 위해서 %[output:416a7b5d]
Cy = randi(50*[-1 1], 2, K)/10;
v = 100;
x = linspace(-6, 6, v)';
Y = zeros(v, K); % 저장할 자리를 미리 확보
for k=1:K %[output:group:5928caf2]
    p = polyfit( Cx(:,k), Cy(:,k), 1); %[output:88742ef0]
    Y(:,k) = polyval(p, x);
end %[output:group:5928caf2]
plot(x,Y,'-',Cx,Cy,'o', "MarkerFaceColor","auto", "LineWidth",2); %[output:9de14e0e]
axis(6*[-1 1 -1 1]); axis square; daspect([1 1 1]); grid on; %[output:9de14e0e]
ax = gca; ax.XTick = []; ax.YTick = []; %[output:9de14e0e]
text(0.5,5,"사랑해요, 엄마,아빠♡", "Color","r"); %[output:9de14e0e]
%%
%[text] ### 세 점을 통과하는 2차 다항식
%[text] 세 점 (-2, -1), (1, 2), (2,1)을 통과하는 2차 다항식은 다음과 같이 구할 수 있습니다.
C = [-2 -1; 1 2; 2 1]; xc = C(:,1); yc = C(:,2);
m = 2; % 다항식의 차수
p = polyfit(xc, yc, m) %[output:33db1c1c]
x = linspace(-3, 4, 100);
y = polyval(p, x);
plot(x, y, 'b-', xc, yc, 'ro', "MarkerFaceColor","auto"); %[output:750fe11d]
grid on; axis equal; %[output:750fe11d]
%%
%[text] #### 10개의 랜덤 세 점을 통과하는 곡선들
%[text] [`randi`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.randi.html)
%[text] $-5 \\sim 5$사이의 랜덤 세 점들을 통과하는 2차 다항식 곡선을 10개 그려볼까요?
n = 3;
K = 10;
Cx = randi(50*[-1 1], n, K)/10;
Cy = randi(50*[-1 1], n, K)/10;
v = 100;
x = linspace(-6, 6, v)';
Y = zeros(v, K); % 자리만 만들기
for k=1:K %[output:group:10b232a8]
    p = polyfit( Cx(:,k), Cy(:,k), n-1); %[output:8f7d5111]
    Y(:,k) = polyval(p, x);
end %[output:group:10b232a8]
plot(x,Y,'-',Cx,Cy,'o', "MarkerFaceColor","auto", "LineWidth",1); %[output:2abdfbee]
axis(6*[-1 1 -1 1]); axis square; daspect([1 1 1]); grid on; %[output:2abdfbee]
ax = gca; ax.XTick = []; ax.YTick = []; %[output:2abdfbee]
%%
%[text] ### 실험 데이터를 가장 잘 표현하는 직선
%[text] 다음은 실험을 통해 측정한 데이터를 나타낸 것입니다. 
%[text] [`scatter`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/scatter.html)
clear; clf; %[output:9a7bcd8c]
load expdata;
scatter(xc, yc, 10, abs(xc+yc)); %산점도 그래프 x값과 y값울 그래프에 뿌려줌  %[output:9a7bcd8c]
%scatter(x값, y삾, 사이즈, 색상) 절댓값으로 두었기에 원점으로부터 멀어질수록 색상이 달라진다
grid on; axis square; daspect([1 1 1]); %[output:9a7bcd8c]
xlabel("$x$", "Interpreter","latex"); %[output:9a7bcd8c]
ylabel("$y$", "Interpreter","latex"); %[output:9a7bcd8c]
%%
%[text] 과연 이 실험 데이터를 가장 잘 나타내는 직선의 방정식은 어떻게 될까요?
p = polyfit(xc, yc, 1) %polynominal 값 구하기 %[output:97b57da8]
%[text] 이 직선의 방정식을 실험 데이터와 함께 나타냅니다.
x = linspace(-100, 100, 2);
y = polyval(p, x); % 구한 polynominal과 x를 매개변수로 polyval에 넣어 y값 구하기 
hold on; plot(x, y, 'b-', "LineWidth", 2); %scatter를 가장 잘 표현한 직선의 방정식 %[output:6d22d393]
hold off; %[output:6d22d393]
%%
%[text] 또 다른 실험 데이터 세트 `(xd, yd)`를 관찰해 보겠습니다.
clear; clf; %[output:24924597]
load expdata;
scatter(xd, yd, 10, abs(xd+yd)); grid on; %[output:24924597]
xlabel("$x$", "Interpreter","latex"); %[output:24924597]
ylabel("$y$", "Interpreter","latex"); %[output:24924597]
%%
%[text] 이 실험 데이터를 가장 잘 나타내는 함수는 직선이 아닌 것 같지만, 일단 직선이라고 가정하고 1차 다항식의 계수를 구해보겠습니다.
p1 = polyfit(xd, yd, 1) %[output:937e79d9]
%[text] 이 직선의 방정식을 실험 데이터와 함께 나타냅니다.
x = linspace(-3, 4, 100);
y1 = polyval(p1, x);
hold on; plot(x, y1, 'b-', "LineWidth", 2); %[output:7df7c60d]
hold off; %[output:7df7c60d]
%[text] 직선은 적당하지 않은 것을 볼 수 있음
%%
%[text] 그렇지만, $x$값이 -2보다 작은 영역을 고려할 때 직선은 적합해 보이지 않습니다. 2차 다항식으로 나타내는 것이 합리적인지 확인해 보겠습니다. 
p2 = polyfit(xd, yd, 2) % 2차 다항식 구하기 %[output:7f8f61b8]
%[text] 이 직선의 방정식을 실험 데이터와 함께 나타냅니다.
figure; scatter(xd, yd, 10, abs(xd+yd)); grid on; %[output:08811e8c]
xlabel("$x$", "Interpreter","latex"); %[output:08811e8c]
ylabel("$y$", "Interpreter","latex"); %[output:08811e8c]
y2 = polyval(p2, x);
hold on; plot(x, y2, 'b-', "LineWidth", 2); %[output:08811e8c]
hold off; %[output:08811e8c]
%[text] x = -3 부근을 보면 일치하지 않는 것을 볼 수 있음 $-\>$2차 그래프도 정확히 표현 못 한다.
%%
%[text] 직선일 때 보다는 실험 데이터를 잘  표현하는 것  같지만 x 값이 -3 ~ -2 범위일 때 실험 데이터의 경향을 따라가지 못하고 있습니다.
%[text] 보다 나은 방정식은 $y=e^{ax+b}$의 식입니다.
%[text] 양 변에 로그를 취하면 다음과 같은 1차 다항식을 얻을 수 있습니다.
%[text] $\\log{y} = ax + b$
p3 = polyfit(xd, log(yd), 1) % log로 exp 지워서 polyfit 사용하여 polynominal 구하기 %[output:9406dd20]
%[text] 이 방정식을 실험 데이터와 함께 나타내면 다음과 같습니다. 
figure; scatter(xd, yd, 10, abs(xd+yd)); grid on; %[output:4ff6a652]
xlabel("$x$", "Interpreter","latex"); %[output:4ff6a652]
ylabel("$y$", "Interpreter","latex"); %[output:4ff6a652]
y3 = exp(polyval(p3, x)); % 다시 exp 취해서 원상태로 돌려주기
hold on;  %[output:4ff6a652]
plot(x, y1, "b-", "LineWidth", 1); %[output:4ff6a652]
plot(x, y2, 'g-', "LineWidth", 1); %[output:4ff6a652]
plot(x, y3, 'r-', "LineWidth", 1); %[output:4ff6a652]
hold off; %[output:4ff6a652]
legend("experiment", "$y=ax+b$", "$y=ax^2+bx+c$", "$y=e^{ax+b}$", ... %[output:4ff6a652]
    "Interpreter", "latex", "Location","best"); %[output:4ff6a652]
ylim([-2 15]); %[output:4ff6a652]
%[text] 이 그래프들을 비교해보면, $y=e^{ax+b}$의 커브가 실험 데이터를 가장 잘 표현하고 있다는 것을 알 수 있습니다.
%%
%[text] #### 커브 피팅 부록: 실험 데이터 생성하기(expdata를 만든 방법)
%[text] - 선형 관계: $y = ax+b$ \
% N = 50;
% xc = randi([-100 100], N, 1);
% yc = 1.1*xc + 1 + 100*rand(N,1);
% scatter(xc, yc, 10, abs(xc+yc));
% grid on; axis square; daspect([1 1 1]);
% save expdata xc yc; %저장
%%
%[text] - 지수 관계: $y = e^{ax+b}$ \
% clear;
% N  = 100;
% xd = 7*rand(N, 1) - 3;
% yd = exp(0.5*xd + rand(N,1));
% scatter(xd, yd, 10, abs(xd+yd));
% grid on;
% save expdata xd yd -append %확장해서 저장
%%
%[text] #### 연습문제 8: 다음 20개의 점을 가장 잘 나타내는  1차 ~ 5차 다항식의 계수를 구하고, 각 다항식의 그래프를 함께 나타내시오.
N = 20;
xp = rand(N,1) * 4*pi - 2*pi;
yp = sin(xp) + 0.5*randn(N,1);
figure; clf; %[output:39ea2aeb]
hold on; %[output:39ea2aeb]
plot(xp, yp, 'bo', 'MarkerSize', 5); %[output:39ea2aeb]
grid on; %[output:39ea2aeb]
axis([-6.5 6.5 -2 2]); %[output:39ea2aeb]
%%
%[text] - 1차 다항식의 계수 \
p1 = polyfit(xp, yp, 1) %[output:98069cb5]
%[text] - 2차 다항식의 계수 \
p2 = polyfit(xp, yp, 2) %[output:430789fa]
%[text] - 3차 다항식의 계수 \
p3 = polyfit(xp, yp, 3) %[output:518d82db]
%[text] - 4차 다항식의 계수 \
p4 = polyfit(xp, yp, 4) %[output:1cba648b]
%[text] - 5차 다항식의 계수 \
p5 = polyfit(xp, yp, 5) %[output:1ed3e5bc]
%[text] - 모든 다항식의 그래프 \
Nx = 200;
x = linspace(-6.5, 6.5, Nx)';
Y = zeros(Nx, 5);
ps = {p1, p2, p3, p4, p5}; % cell data: 개수(크기)가 다른 것은 cell 속에 넣음
for k=1:5
    Y(:,k) = polyval(ps{k}, x); %ps의 1~5번째 값Code line 310     Y(:,k) = polyval(ps{k}, x); %ps의 1~5번째 값

end
hold on; %[output:4e579f47]
plot(x, Y, 'LineWidth',1); %[output:4e579f47]
hold off; %[output:4e579f47]
legend("data", "1차", "2차", "3차", "4차", "5차", "Location","northeastoutside"); %[output:4e579f47]
%%
%[text] ## 인터폴레이션 (Interpolation)
%[text] 인터폴레이션은 주어진 점들의 사잇값을 찾아 줍니다.
%[text] [`interp1`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.interp1.html)
%[text] ### `사인 함수값 샘플로부터 사잇값 찾기`
clear;
xp = 0:10;
yp = sin(xp);
x  = 0:0.1:10;

% Spline interpolation
y =  interp1(xp, yp, x, 'spline');

% Plotting for comparison
plot(xp, yp, 'o:', x, y, '-'); %[output:823af4ca]
grid on; %[output:823af4ca]
legend('Data points', 'Spline', "Location","northeastoutside"); %[output:823af4ca]
%%
%[text] 인터폴레이션 알고리즘은 'spline'외에도 'pchip', 'makima' 등을 사용할 수 있습니다. 
%[text] 자세한 내용은 아래 링크를 통해 확인하실 수 있습니다. 
%[text] [`interp1`](https://kr.mathworks.com/help/releases/R2025b/matlab/ref/double.interp1.html)
%%
%[text] #### `연습문제 9: 위 그래프에서 11개의 점을 지나는 10차 다항식의 계수를 구하고 'spline' 인터폴레이션으로 구한 사잇값과 비교하시오.`
p = polyfit(xp, yp, 10);
y1 = polyval(p, x);
hold on; plot(x, y1, 'k-'); hold off; %[output:32d2b638]
%[text] 그래프를 그려보면 두 곡선이 매우 유사한 것을 관찰할 수 있습니다. 
%[text] 그렇지만 'spline' 알고리즘은 연속된 3개의 점들을 3차 다항식으로 커브 피팅합니다. 다만 연속된 3차 다항식들이 차례 차례 매우 부드럽게 연결되도록 만들어 줍니다. 한편, 10차 다항식은 11개의 모든 점들을 통과하는 1개의 다항식입니다. Data Points의 갯수가 많아질 수록 모든 점들을 통과하는 고차 다항식의 계수를 구하는 것은 계산이 복잡하고 시간이 걸리는 연산을 하게 됩니다. 인터폴레이션은 이 계산을 상대적으로 간단한게 해주면서도 각 점들을 부드럽게 연결해 줍니다.
%%
%[text] ### 2차원 공간에서의 인터폴레이션
%[text] 2차원에 있는 $\\{ (x\_n,y\_n)| n=1\\sim N\\}$점들을 부드럽게 잇는 곡선을 구하기 위해서는 $x$축과 $y$축에 대해 각각 `interp1`을 적용하면 됩니다. 다음 예제는 $N$개의 랜덤 점들을 부드럽게 연결하는 폐곡선을 찾는 방법입니다.
%[text] #### 부드러운 폐곡선
clear; clf; %[output:6ca04489]
% Parameters
N  = 4; % number of random points
M  = 3; % number of cycles
K  = M*1000; % number of curve points 점과 점 사이

% N number of random points
C  = rand(N,2); xd = C(:,1); yd = C(:,2); 
plot( xd, yd, 'bo', 'MarkerSize', 3); %[output:6ca04489]
for u=1:N
    text(xd(u)+0.02, yd(u)+0.04, sprintf("%d",u)); %[output:6ca04489]
end

% Interpolation
n  = (0:M*N)'; % number of data points
xp = [repmat(xd,M,1); xd(1)]; % x-coordinate of data points
yp = [repmat(yd,M,1); yd(1)]; % y-coordinate of data points
k  = linspace(0,M*N,K)'; % fractional index
x  = interp1(n, xp, k, 'spline');
y  = interp1(n, yp, k, 'spline');

% Interpolated smooth curve
hold on;  %[output:6ca04489]
X = reshape(x, [], M); Y = reshape(y, [], M);
plot(X(:,M-1), Y(:,M-1), '-'); % 부드러운 곡선 추가 %[output:6ca04489]
hold off; %[output:6ca04489]
axis([-0.2 1.2 -0.2 1.2]); daspect([1 1 1]); grid on; %[output:6ca04489]

ax = gca; ax.XTick = -0.2:0.2:1.2; %[output:6ca04489]
%%
%[text] #### 심화 관찰
figure; %[output:6716254d]
plot(k(1:1000), X); %[output:6716254d]
legend("Location","northeastoutside"); %[output:6716254d]
figure; plot(X,Y); grid on; %[output:8bee453e]
daspect([1 1 1]); legend("Location","northeastoutside"); %[output:8bee453e]
hold on; plot( xd, yd, 'bo', 'MarkerSize', 3); hold off; %[output:8bee453e]
for u=1:N %[output:group:9230e567]
    text(xd(u)+0.02, yd(u)+0.04, sprintf("%d",u-1)); %[output:8bee453e]
end %[output:group:9230e567]
%[text] 1st cycle에서는 0~3까지가 'spline' 인터폴레이션 시작의 영향을 받고, 3rd cycle에서는 1~4까지가 끝의 영향을 받는 것을 관찰할 수 있습니다. 2nd cycle의 0~4까지 모든 구간은 이러한 영향이 없으므로 전 구간에서 부드럽게 연결됩니다. 이 때문에 위 폐곡선에서는 $M$개의 cycle가운데 $M-1$번째를 선택하여 사용하고 있습니다. 즉, $M=3$일 때 2nd cycle 값을 사용합니다. 한편 $M \> 3$인 경우 2nd cycle ~ $M-1$ cycle의 값은 같습니다. 예를 들어 $M=5$일 때 2nd cycle, 3rd cycle, 4th cycle의 값은 모두 같습니다.  이러한 이유때문에 $M=5$로 설정하고 위 그래프를 그려보면 서로 다른 곡선이 3개밖에 관찰되지 않습니다. 
%[text] - 관찰 결과: 'spline' 인터폴레이션은 첫 4개와 마지막 4개 데이터 포인트들의 사잇값을 계산할 때 끝점 효과(end effect)의 영향을 받습니다.  \
%%
%[text] #### 조약돌 만들기
%[text] 조약돌을 여러개 가져와서 여러 곳에 둡니다. 
%[text] 조약돌의 좌표는 위에서 만든 폐곡선 코드를 함수로 만든 pebble을 호출하여 생성합니다.
help pebble %[output:53057f73]
%%
%[text] $N$number of pebble curves
clear; clf;
% Curves of Pebbles
N =   10;   % number of pebbles
K = 1000; % number of points in a pebble
X = zeros(K,N); Y = zeros(K,N);
for n=1:N %[output:group:42e25486]
    [x, y] = pebble(1.5, 0.2, 5, K); %[output:643fde44]
    r      = 0.5 + rand;
    X(:,n) = randi(10*[-7 7])/10 + r*x;
    Y(:,n) = randi(10*[-5 5])/10 + r*y;
end %[output:group:42e25486]
%[text] 바닷물 배경색에 조약돌을 담그어 보겠습니다. figure의 배경색을 설정합니다. 
%[text] ![](text:image:21af)
c = 1:N;
colormap turbo;
fig = figure("Position", [0 0 600 400], "Color",[127, 255, 212]/255); % Aquamarine
ax  = axes(fig);
ax.Position = [0 0 1 1]; % figure 창에 꽉 차게 그래프를 나타냅니다.
patch(ax, X,Y,c, "EdgeColor", "none", "FaceAlpha", 0.2);
axis(5*[-1.5 1.5 -1 1]); % 3:2 ratio --> 600:400 pixels
daspect([1 1 1]); axis off;
%%
%[text] ### 네이버 지도에 경로 나타내기
%[text] 1. 네이버에서 지도 이미지를 선택하여 저장합니다.
%[text] 2. 지도 이미지 크기에 맞도록 Figure 창을 생성하고 전체를 채워서 나타냅니다.
%[text] 3. 마우스로 경로를 선택합니다. 경로를 종료하기 위해서는 ENTER 키를 누릅니다.
%[text] 4. 최종 목적지에 나타낼 메시지를 추가합니다. \
%[text] 참고: [`imagesc`](https://kr.mathworks.com/help/matlab/ref/imagesc.html)
%[text] 지도 이미지를 읽어들여 정보 확인
C = imread('naver_map.png'); % 현재 폴더에 있는 이미지 
[H, W, ~] = size(C); 
%[text] figure 창에 이미지를 꽉 채워 나타냄
fig = figure("Position",[0 0 W H], "Visible","on"); %[output:717d17bc]
ax  = gca; set(ax, "InnerPosition", [0 0 1 1]); %[output:717d17bc]
I   = imagesc(C); axis off;  %[output:717d17bc]
%[text] 
%
% 마우스로 경로 선택하기
% - 마우스를 클릭하거나 아무 키를 누르면 현재 커서 지점 선택
nMax = 100; % 최대 경로 지점 수
x = zeros(nMax,1); y = zeros(nMax,1);
n = 0; % 선택한 경로 지점 수
hold on; %[output:717d17bc]
for k = 1:nMax
    [x0, y0] = ginput(1); %[output:717d17bc]
    if isempty(x0)
        break; % ENTER 키를 누르면 경로 지정 완료
    else
        % 선택한 경로지점 추가하기
        x(k) = x0; y(k) = y0;
        plot(x0, y0, 'ro');
        n = n + 1;
    end
end

%
% 지도에 경로 나타내기
%
nPointsInPath = 200; % 전체 경로를 200개의 점으로 인터폴레이션
if n > 2
    k  = 0:n-1;
    dx = diff(x); dy = diff(y);
    ds = sqrt(dx.^2 + dy.^2); % 각 구간의 길이
    ks = round(ds(1:n-1)/sum(ds(1:n-1))*nPointsInPath);
    ki = [];
    for i=1:n-1
        ki = [ki, linspace(i-1,i,ks(i))];
    end

    % 인터폴레이션을 통해 부드러운 경로 좌표 구하기
    xi = interp1( k', x(1:n), ki', 'pchip' );
    yi = interp1( k', y(1:n), ki', 'pchip' );

    comet(xi, yi ); % 경로 추적 애니메이션 %[output:717d17bc]
    plot(xi, yi, 'r-', 'LineWidth', 2); %[output:717d17bc]
end
plot(x([1,n]), y([1,n]), "ro", "MarkerSize", 10); %[output:717d17bc]

%
% 메시지 남기기
%
[x0, y0] = ginput(1); %[output:717d17bc]
msg = inputdlg("남길 메시지","메시지", [2 40]);
text(x0, y0, msg, "FontSize", 20, "Color","r"); %[output:717d17bc]

hold off; %[output:717d17bc]

%%
%[text] #### Plot on the Live Map
figure("Visible","on"); % Detatch the figure window %[output:7018a7e9]

% region of interest on the global map
lat = [ 37.3794  37.3741  37.3728  37.3705  37.3762];
lon = [126.6325 126.6267 126.6279 126.6325 126.6378];
geoplot(lat,lon,"bx"); %[output:7018a7e9]
geobasemap streets-ligh; %streets; % streets-light, satellite, bluegreen %[output:7018a7e9]
hold on; %[output:7018a7e9]

% Select your path by a set of waypoints.
nMax = 100;
x = zeros(nMax,1); y = zeros(nMax,1);
n = 0; % number of points entered
for k = 1:nMax
    [x0, y0] = ginput(1); %[output:7018a7e9]
    if isempty(x0)
        break;
    else
        x(k) = x0; y(k) = y0;
        geoplot(x0, y0, 'ro');
        n = n + 1;
    end
end

% Show your path on the map.
if n > 2
    k  = 0:n-1;
    dx = diff(x); dy = diff(y);
    ds = sqrt(dx.^2 + dy.^2);
    ks = round(ds(1:n-1)/sum(ds(1:n-1))*500);
    ki = [];
    for i=1:n-1
        ki = [ki, linspace(i-1,i,ks(i))];
    end

    xi = interp1( k', x(1:n), ki', 'pchip' ); %가는 것은 pchip이 더 좋다.
    yi = interp1( k', y(1:n), ki', 'pchip' );

    comet( xi, yi ); %[output:7018a7e9]
    geoplot( xi, yi, 'r-', 'LineWidth', 2); %[output:7018a7e9]
end
hold off; %[output:7018a7e9]
%%
%[text] ## Show on the interactive map
uif = uifigure;
g = geoglobe(uif, "Basemap","satellite");  %[control:dropdown:36b7]{"position":[29,40]} %[output:86d6f21e]
ht  = ones(size(xi))*200;
geoplot3(g, xi(1:3:end), yi(1:3:end), ht(1:3:end), 'r-', "LineWidth", 2);
